    quiz: [{ q: "À quoi servent les quipus ?", a: "À enregistrer des informations administratives, souvent numériques." }, { q: "Pourquoi les routes comptent-elles ?", a: "Elles relient un empire andin très dispersé." }, { q: "Quel piège éviter ?", a: "Croire qu’absence d’alphabet signifie absence d’administration." }, { q: "Quels éléments composent un quipu ?", a: "Cordes, nœuds, couleurs et positions." }, { q: "Quelle idée retenir ?", a: "L’information peut circuler sans livre ni alphabet." }]
