  document.querySelectorAll("[data-remove-friend]").forEach(btn => btn.addEventListener("click", event => { event.stopPropagation(); removeFriend(btn.dataset.removeFriend); }));
  $(`[data-add-friend]`)?.addEventListener("submit", addFriend);
